queries.sparql:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?methodname WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasTechniques ?child ; p:hasSound_Designers ?parent . } GROUP BY ?child }
  ?child p:MethodName ?methodname .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Sound_Designers } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?name ?methodname WHERE {
  ?sound_designer_technique a :Sound_Designer_Technique .
  ?techniques a :Techniques .
  ?sound_designer_technique p:hasTechniques ?techniques .
  ?sound_designers a :Sound_Designers .
  ?sound_designer_technique p:hasSound_Designers ?sound_designers .
  ?sound_designers p:name ?name .
  ?techniques p:MethodName ?methodname .
} }
  collective: { SELECT ?methodname WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasTechniques ?child ; p:hasSound_Designers ?parent . } GROUP BY ?child }
  ?child p:MethodName ?methodname .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Sound_Designers } }
  FILTER(?nf = ?total)
} }
}
